parameters.jsCode:
const raw = $json.choices[0].message.content;

const cleaned = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  return {
    json: {
      parse_error: true,
      raw_output: raw,
      cleaned_output: cleaned,
      error_message: error.message
    }
  };
}

const job = $('Add Description').item.json;
const rawScore = Number(parsed.fit_score);
const normalizedScore = rawScore <= 1 ? rawScore * 100 : rawScore;

return {
  json: {
    job_url: job.job_url,
    job_title: job.job_title,
    company: job.company,
    source: job.source,
    location: job.location,
    description: job.description,
    fit_score: Math.round(normalizedScore),
    matched_skills: parsed.matched_skills || [],
    missing_skills: parsed.missing_skills || [],
    summary: parsed.summary || "",
    reason: parsed.reason || "",
    recommendation: parsed.recommendation || ""
  }
};

return {
  json: {
    job_url: $json.job_url || $json.jobUrl || $json.url || "",
    job_title: $json.job_title || $json.title || "",
    company: $json.company || $json.companyName || "",
    source: "linkedin",
    location: $json.location || "",
    description: $json.description || $json.jobDescription || ""
  }
};

const items = $input.all();

const levelKeywords = [
  "intern",
  "junior",
  "trainee",
  "entry level"
];

const domainKeywords = [
  "ai",
  "ml",
  "machine learning",
  "artificial intelligence",
  "data",
  "data science",
  "data engineer",
  "software engineer",
  "cloud",
  "python",
  "backend"
];

const badKeywords = [

  "lead",
  "senior",
  "principal",
  "manager",
  "director",
  "marketing",
  "sales",
  "designer",
  "recruiter",
  "accountant",
  "hr"
];

return items.filter(item => {
  const title = (item.json.job_title || "").toLowerCase().replace(/[^a-z0-9\s/.-]/g, " ");

  const hasLevel = levelKeywords.some(k => title.includes(k));
  const hasDomain = domainKeywords.some(k => title.includes(k));
  const hasBad = badKeywords.some(k => title.includes(k));

  return hasLevel && hasDomain && !hasBad;
});

const html = $json.data || "";
let description = "";

const match = html.match(
  /<div class="show-more-less-html__markup[^>]*>([\s\S]*?)<\/div>\s*<button class="show-more-less-html__button/i
);

if (match) {
  description = match[1]
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/strong>/gi, "\n")
    .replace(/<strong>/gi, "")
    .replace(/<\/li>/gi, "\n")
    .replace(/<li>/gi, "• ")
    .replace(/<\/ul>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/\n{2,}/g, "\n")
    .replace(/[ \t]{2,}/g, " ")
    .replace(/\n +/g, "\n")
    .trim();
}

const base = $('Job filter').item.json;

return {
  json: {
    job_url: base.job_url,
    job_title: base.job_title,
    company: base.company,
    source: base.source,
    location: base.location,
    description: description
  }
};
